WHERE
    B.DELETE_FLG='0'
    AND A.BUTEN_CODE = B.BRANCH_NO
    AND LPAD(A.ACCOUNT_NUMBER,6,'0') = B.ACCOUNT_NO



                AND(A.BROKER_CODE IN


                        ) OR A.BROKER_CODE IN(


                        ,

                    #{brokerChargeList.brokerCode}

                )


                AND((A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN


                        ) OR (A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN(


                        ,

                    (#{brokerChargeList.brokerCode},#{brokerChargeList.empCode})

                )




        AND A.BROKER_CODE IN

            #{brokerCode}



        AND A.BROKER_CODE NOT IN

            #{brokerCode}



        AND A.INTERMEDIARY_EMP_CD = #{req.empCode}


        AND A.BUTEN_CODE = #{req.butenCode}


        AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})


        AND ((A.NAME_KANJI = #{req.customerNameKanjiKana})
        OR (A.NAME_KANA = #{req.customerNameKanjiKana}))


        AND ((A.NAME_KANJI LIKE #{req.customerNameKanjiKana} || '%')
        OR (A.NAME_KANA LIKE #{req.customerNameKanjiKana} || '%'))


        AND ((A.NAME_KANJI LIKE '%' || #{req.customerNameKanjiKana} || '%' )
        OR (A.NAME_KANA LIKE '%' || #{req.customerNameKanjiKana} || '%' ))


        AND A.CUSTOMER_ATTRIBUTE IN

                #{tradeCourse}


    AND A.BROKER_CODE = E.BROKER_CODE
    AND E.BROKER_BRANCH_KIND = '00'

        AND C.BROKER_BRANCH_CODE = #{req.branchCode}
